  const { data, ...query } = useQuery({
    queryKey: ['products'],
    queryFn: fetchProducts,
    // Utiliser les données du cache si hors ligne
    initialData: () => {
      if (!isOnline) {
        const cached = localStorage.getItem('cachedProducts');
        return cached ? JSON.parse(cached) : null;
      }
      return null;
    },
    onSuccess: (data) => {
      // Mettre à jour le cache quand en ligne
      localStorage.setItem('cachedProducts', JSON.stringify(data));
      localStorage.setItem('lastCacheUpdate', Date.now());
    }
  });

  return { data, ...query };
};

