// components/ErrorBoundary.jsx
import React from 'react';

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    // Met à jour l'état pour afficher l'UI de repli
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // Logguer l'erreur vers un service externe (Sentry, LogRocket)
    console.error('ErrorBoundary caught an error:', error, errorInfo);
    this.setState({ errorInfo });

    // Envoyer à un service de monitoring
    if (window.Sentry) {
      window.Sentry.captureException(error, { extra: errorInfo });
    }
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null, errorInfo: null });
    // Optionnel : recharger les données ou réinitialiser l'état de l'application
    if (this.props.onReset) {
      this.props.onReset();
    }
  };

  render() {
    if (this.state.hasError) {
      // UI de repli personnalisée
      return (
        <div className="min-h-[400px] flex items-center justify-center p-6">
          <div className="text-center max-w-md mx-auto">
            <div className="text-6xl mb-4">🐛</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">
              Oups ! Une erreur est survenue
            </h2>
            <p className="text-gray-600 mb-6">
              {this.props.fallbackMessage || 
                "L'application a rencontré un problème inattendu. L'équipe technique a été notifiée."}
            </p>
            <div className="flex gap-4 justify-center">
              <button
                onClick={() => window.location.reload()}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
              >
                ↻ Recharger la page
              </button>
              <button
                onClick={this.handleReset}
                className="bg-gray-200 text-gray-800 px-4 py-2 rounded-lg hover:bg-gray-300"
              >
                Réessayer
              </button>
            </div>
            {/* Affichage des détails en développement uniquement */}
            {process.env.NODE_ENV === 'development' && this.state.error && (
              <details className="mt-6 text-left bg-gray-100 p-3 rounded">
                <summary className="cursor-pointer font-mono text-sm">
                  Détails techniques
                </summary>
                <pre className="text-xs mt-2 overflow-auto">
                  {this.state.error.toString()}
                  {this.state.errorInfo?.componentStack}
                </pre>
              </details>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

// Utilisation dans l'application
<ErrorBoundary fallbackMessage="Erreur dans le catalogue produits">
  <ProductsPage />
</ErrorBoundary>

// Alternative avec react-error-boundary (bibliothèque)
